// Hash function for pair<uint32_t, uint32_t>
struct pair_hash {
  std::size_t operator()(const std::pair<uint32_t, uint32_t> &p) const {
    return std::hash<uint64_t>()((uint64_t(p.first) << 32) | p.second);
  }
};

